const quotes = [
  { id: 1, text: "与天奋斗，其乐无穷！与地奋斗，其乐无穷！与人奋斗，其乐无穷！", source: "《奋斗自勉》1917年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 2, text: "革命不是请客吃饭，不是做文章，不是绘画绣花，不能那样雅致，那样从容不迫，文质彬彬，那样温良恭俭让。", source: "《湖南农民运动考察报告》1927年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 3, text: "凡是敌人反对的，我们就要拥护；凡是敌人拥护的，我们就要反对。", source: "《和中央社、扫荡报、新民报三记者的谈话》1939年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 4, text: "人是要有一点精神的。", source: "《纪念白求恩》1939年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 5, text: "一切反动派都是纸老虎。看起来，反动派的样子是可怕的，但是实际上并没有什么了不起的力量。", source: "《和美国记者安娜·路易斯·斯特朗的谈话》1946年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 6, text: "在战略上要藐视敌人，在战术上要重视敌人。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 7, text: "下定决心，不怕牺牲，排除万难，去争取胜利。", source: "《愚公移山》1945年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 8, text: "我们的原则是党指挥枪，而决不容许枪指挥党。", source: "《战争和战略问题》1938年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 9, text: "斗争，失败，再斗争，再失败，再斗争，直至胜利——这就是人民的逻辑。", source: "《丢掉幻想，准备斗争》1949年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 10, text: "帝国主义和一切反动派都是纸老虎。", source: "《帝国主义和一切反动派都是纸老虎》1958年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 11, text: "我们不但善于破坏一个旧世界，我们还将善于建设一个新世界。", source: "《中国人民站起来了》1949年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 12, text: "革命的道路是曲折的，前途是光明的。", source: "《关于目前党的政策中的几个重要问题》1948年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 13, text: "凡事预则立，不预则废。", source: "《关于领导方法的若干问题》1943年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 14, text: "没有调查，没有发言权。", source: "《反对本本主义》1930年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 15, text: "世界上怕就怕'认真'二字，共产党就最讲认真。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 16, text: "我们共产党人好比种子，人民好比土地。我们到了一个地方，就要同那里的人民结合起来，在人民中间生根、开花。", source: "《关于重庆谈判》1945年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 17, text: "虚心使人进步，骄傲使人落后。", source: "《中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 18, text: "战略上藐视敌人，战术上重视敌人，这是我们战胜敌人的基本原则之一。", source: "《关于目前国际形势的几点估计》1946年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 19, text: "我们的任务是过河，但是没有桥或没有船就不能过。不解决桥或船的问题，过河就是一句空话。", source: "《关于领导方法的若干问题》1943年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 20, text: "人民，只有人民，才是创造世界历史的动力。", source: "《论联合政府》1945年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 21, text: "中国人民有志气，有能力，一定要在不远的将来，赶上和超过世界先进水平。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 22, text: "一个人做点好事并不难，难的是一辈子做好事，不做坏事，这才是最难最难的啊！", source: "《纪念白求恩》1939年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 23, text: "敌进我退，敌驻我扰，敌疲我打，敌退我追。", source: "《中国革命战争的战略问题》1936年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 24, text: "打得赢就打，打不赢就走。", source: "《中国革命战争的战略问题》1936年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 25, text: "革命战争是群众的战争，只有动员群众才能进行战争，只有依靠群众才能进行战争。", source: "《关心群众生活，注意工作方法》1934年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 26, text: "我们应当相信群众，我们应当相信党，这是两条根本的原理。如果怀疑这两条原理，那就什么事情也做不成了。", source: "《关于农业合作化问题》1955年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 27, text: "在这个世界上，事情是复杂的，是由各方面因素决定的。看问题要从各方面去看，不能只从单方面看。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 28, text: "要奋斗就会有牺牲，死人的事是经常发生的。但是我们想到人民的利益，想到大多数人民的痛苦，我们为人民而死，就是死得其所。", source: "《为人民服务》1944年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 29, text: "我们的共产党和共产党所领导的八路军、新四军，是革命的队伍。我们这个队伍完全是为着解放人民的，是彻底地为人民的利益工作的。", source: "《为人民服务》1944年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 30, text: "一切革命斗争都是为着解决这个矛盾而存在的。", source: "《矛盾论》1937年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 31, text: "不打无准备之仗，不打无把握之仗。", source: "《中国革命战争的战略问题》1936年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 32, text: "集中优势兵力，各个歼灭敌人。", source: "《集中优势兵力，各个歼灭敌人》1946年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 33, text: "我们的目的一定要达到。我们的目的一定能够达到。", source: "《抗日战争胜利后的时局和我们的方针》1945年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 34, text: "革命是历史的火车头。", source: "《湖南农民运动考察报告》1927年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 35, text: "只要我们能够学习，我们就一定能够克服困难，我们就一定能够战胜敌人。", source: "《关于重庆谈判》1945年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 36, text: "严重的问题是教育农民。", source: "《论人民民主专政》1949年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 37, text: "马克思主义的道理千条万绪，归根结底，就是一句话：造反有理。", source: "《在延安各界庆祝斯大林六十寿辰大会上的讲话》1939年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 38, text: "我们的事业是正义的。正义的事业是任何敌人也攻不破的。", source: "《论持久战》1938年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 39, text: "中国人民有自己的民族自尊心和自豪感，以热爱祖国、贡献自己的全部力量建设社会主义祖国为最大光荣，以损害社会主义祖国利益、尊严和荣誉为最大耻辱。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 40, text: "帝国主义者的逻辑和人民的逻辑是这样的不同：帝国主义者说，你们没有资格讲人权，因为你们是弱小民族；人民说，正因为你们压迫我们，所以我们要斗争。", source: "《丢掉幻想，准备斗争》1949年", tag: "斗争哲学", context: "维护人际关系的本质不是讨好、退让，而是它的对立面——斗争。" },
  { id: 41, text: "实践、认识、再实践、再认识，这种形式，循环往复以至无穷，而实践和认识之每一循环的内容，都比较地进到了高一级的程度。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 42, text: "通过实践而发现真理，又通过实践而证实真理和发展真理。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 43, text: "马克思主义者认为，只有人们的社会实践，才是人们对于外界认识的真理性的标准。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 44, text: "读书是学习，使用也是学习，而且是更重要的学习。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 45, text: "一切真知都是从直接经验发源的。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 46, text: "感觉只解决现象问题，理论才解决本质问题。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 47, text: "认识的能动作用，不但表现于从感性的认识到理性的认识之能动的飞跃，更重要的还须表现于从理性的认识到革命的实践这一个飞跃。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 48, text: "人们要想得到工作的胜利即得到预想的结果，一定要使自己的思想合于客观外界的规律性，如果不合，就会在实践中失败。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 49, text: "批评和自我批评是我们党的优良传统，是我们党区别于其他任何政党的显著标志之一。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 50, text: "理论与实践的统一，是马克思主义的一个最基本的原则。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 51, text: "要了解情况，唯一的方法是向社会作调查。", source: "《反对本本主义》1930年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 52, text: "没有正确的政治观点，就等于没有灵魂。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 53, text: "知识的问题是一个科学问题，来不得半点的虚伪和骄傲，决定地需要的倒是其反面——诚实和谦逊的态度。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 54, text: "我们必须学会全面地看问题，不但要看到事物的正面，也要看到它的反面。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 55, text: "主观和客观、理论和实践、知和行的具体的历史的统一，反对一切离开具体历史的'左'的或右的错误思想。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 56, text: "实践是检验真理的唯一标准。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 57, text: "我们的任何工作，都要从实际出发，而不是从主观愿望出发。", source: "《反对本本主义》1930年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 58, text: "调查就像'十月怀胎'，解决问题就像'一朝分娩'。调查就是解决问题。", source: "《反对本本主义》1930年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 59, text: "人类的历史，就是一个不断地从必然王国向自由王国发展的历史。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 60, text: "马克思主义的哲学认为，十分重要的问题，不在于懂得了客观世界的规律性，因而能够解释世界，而在于拿了这种对于客观规律性的认识去能动地改造世界。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 61, text: "凡是主观主义者，都是不从实际出发，而是从主观出发的。", source: "《整顿党的作风》1942年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 62, text: "一切从实际出发，理论联系实际，实事求是，在实践中检验真理和发展真理。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 63, text: "人们在社会实践中从事各项斗争，有了丰富的经验，有成功的，有失败的。无数客观外界的现象通过人的眼、耳、鼻、舌、身这五个官能反映到自己的头脑中来，开始是感性认识。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 64, text: "真正的知识只能通过直接经验才能获得。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 65, text: "一切实践的东西，都是从理论出发的，没有革命的理论，就没有革命的运动。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 66, text: "只有在实践中，才能检验出理论的正确与否。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 67, text: "要想知道梨子的滋味，就得变革梨子，亲口尝一尝。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 68, text: "如果有了正确的理论，只是把它空谈一阵，束之高阁，并不实行，那末，这种理论再好也是没有意义的。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 69, text: "在实践中，人们不但认识了自然界的规律性，因而能够解释自然，而且还运用对于自然界规律性的认识去能动地改造自然。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 70, text: "我们看事情必须要看它的实质，而把它的现象只看作入门的向导，一进了门就要抓住它的实质，这才是可靠的科学的分析方法。", source: "《星星之火，可以燎原》1930年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 71, text: "没有文化的军队是愚蠢的军队，而愚蠢的军队是不能战胜敌人的。", source: "《论联合政府》1945年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 72, text: "学习的敌人是自己的满足，要认真学习一点东西，必须从不自满开始。", source: "《中国共产党在民族战争中的地位》1938年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 73, text: "对于马克思主义的理论，要能够精通它、应用它，精通的目的全在于应用。", source: "《整顿党的作风》1942年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 74, text: "我们是马克思主义者，马克思主义叫我们看问题不要从抽象的定义出发，而要从客观存在的事实出发。", source: "《反对党八股》1942年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 75, text: "理论是灰色的，生命之树常青。", source: "《实践论》1937年", tag: "实践论", context: "知识不是从书本上得来的，而是从实践中得来的。行动，才是认识的起点。" },
  { id: 76, text: "矛盾是普遍的、绝对的，存在于事物发展的一切过程中，又贯串于一切过程的始终。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 77, text: "事物的矛盾法则，即对立统一的法则，是唯物辩证法的最根本的法则。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 78, text: "在复杂的事物的发展过程中，有许多的矛盾存在，其中必有一种是主要的矛盾，由于它的存在和发展，规定或影响着其他矛盾的存在和发展。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 79, text: "矛盾的主要方面和非主要方面互相转化着，事物的性质也就随着起变化。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 80, text: "对立统一规律是宇宙的根本规律。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 81, text: "两个相反的东西中间有同一性，所以二者能够共处于一个统一体中，又能够互相转化，这是辩证法的基本道理。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 82, text: "矛盾着的对立面又统一，又斗争，由此推动事物的运动和变化。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 83, text: "研究问题，忌带主观性、片面性和表面性。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 84, text: "世界上没有绝对地不包含矛盾的事物，没有矛盾就没有世界。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 85, text: "任何过程如果有多数矛盾存在的话，其中必定有一种是主要的，起着领导的、决定的作用，其他则处于次要和服从的地位。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 86, text: "矛盾的特殊性，就是说，矛盾的各种不同的特殊性，是我们认识矛盾的基础。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 87, text: "不同质的矛盾，只有用不同质的方法才能解决。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 88, text: "一切事物中包含的矛盾方面的相互依赖和相互斗争，决定一切事物的生命，推动一切事物的发展。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 89, text: "矛盾的普遍性或绝对性这个问题有两方面的意义。其一是说，矛盾存在于一切事物的发展过程中；其二是说，每一事物的发展过程中存在着自始至终的矛盾运动。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 90, text: "矛盾的斗争性是无条件的、绝对的，矛盾的同一性是有条件的、相对的。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 91, text: "辩证法的宇宙观，不论在中国，在欧洲，在古代，都是产生的。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 92, text: "我们中国人常说：'相反相成。'就是说相反的东西有同一性。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 93, text: "事物的矛盾，分析其各方面的具体情况，找出解决矛盾的正确方法，这就是我们的任务。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 94, text: "在同一性中存在着斗争性，在特殊性中存在着普遍性，在个性中存在着共性。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 95, text: "矛盾的同一性，就是说，一切矛盾着的方面都因一定条件具备着同一性，因而能够共处于一个统一体中，又能够互相转化到相反的方面去。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 96, text: "在人类的认识史中，从来就有关于宇宙发展法则的两种见解，一种是形而上学的见解，一种是辩证法的见解，形成了互相对立的两种宇宙观。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 97, text: "矛盾的普遍性和矛盾的特殊性的关系，就是矛盾的共性和个性的关系。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 98, text: "人们在认识上的辩证法，就是这样的：从特殊到一般，又从一般到特殊。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 99, text: "矛盾的斗争贯串于过程的始终，并使一过程向他过程转化，矛盾的斗争无所不在。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 100, text: "矛盾的各方面，不能孤立地存在。假如没有和它作对的矛盾的方面，它自己这一方面就失去了存在的条件。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 101, text: "没有什么事物是不包含矛盾的，没有矛盾就没有世界。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 102, text: "辩证唯物论的宇宙观主张从事物的内部、从一事物对他事物的关系去研究事物的发展，即把事物的发展看做是事物内部的必然的自己的运动。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 103, text: "每一事物内部都有其新旧两个方面的矛盾，形成一系列的曲折的斗争。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 104, text: "矛盾的解决，就是矛盾的转化，就是旧的矛盾消灭，新的矛盾产生。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 105, text: "矛盾的存在，是宇宙间的绝对的东西，矛盾的解决，则是相对的东西，因为每一矛盾的解决，都会产生新的矛盾。", source: "《矛盾论》1937年", tag: "矛盾论", context: "世间万物皆有矛盾，认清矛盾的主次，才能找到解决问题的关键所在。" },
  { id: 106, text: "全心全意地为人民服务，一刻也不脱离群众；一切从人民的利益出发，而不是从个人或小集团的利益出发。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 107, text: "为什么人的问题，是一个根本的问题，原则的问题。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 108, text: "我们应该深刻地注意群众生活的问题，从土地、劳动问题，到柴米油盐问题。", source: "《关心群众生活，注意工作方法》1934年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 109, text: "从群众中来，到群众中去。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 110, text: "凡属正确的领导，必须是从群众中来，到群众中去。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 111, text: "群众是真正的英雄，而我们自己则往往是幼稚可笑的，不了解这一点，就不能得到起码的知识。", source: "《农村调查》1941年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 112, text: "共产党人的一切言论行动，必须以合乎最广大人民群众的最大利益，为最广大人民群众所拥护为最高标准。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 113, text: "我们的责任，是向人民负责。每句话，每个行动，每项政策，都要适合人民的利益，如果有了错误，定要改正，这就叫向人民负责。", source: "《为人民服务》1944年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 114, text: "我们的文艺是为什么人的？这个问题，本来是马克思主义者特别是列宁所早已解决了的。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 115, text: "人民群众有无限的创造力。他们可以组织起来，向一切可以发挥自己力量的地方和部门进军，向生产的深度和广度进军。", source: "《组织起来》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 116, text: "只要我们依靠人民，坚决地相信人民群众的创造力是无穷无尽的，因而信任人民，和人民打成一片，那就任何困难也能克服，任何敌人也不能压倒我们，而只会被我们所压倒。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 117, text: "人民是历史的创造者，是真正的英雄。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 118, text: "领导者的责任，归结起来，主要地是出主意、用干部这两件事。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 119, text: "我们党的工作作风，就是联系群众，就是批评和自我批评，就是民主集中制。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 120, text: "要把人民群众的利益放在第一位，把个人利益放在第二位。", source: "《为人民服务》1944年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 121, text: "我们共产党人，是以全心全意为人民服务为宗旨的。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 122, text: "群众的眼睛是雪亮的。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 123, text: "我们的干部要关心每一个战士，一切革命队伍的人都要互相关心，互相爱护，互相帮助。", source: "《为人民服务》1944年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 124, text: "任何工作任务的执行，都要通过一定的工作方法才能实现。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 125, text: "在我党的一切实际工作中，凡属正确的领导，必须是从群众中来，到群众中去。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 126, text: "我们应该把人民群众的利益当作自己的利益，把人民群众的疾苦当作自己的疾苦。", source: "《关心群众生活，注意工作方法》1934年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 127, text: "凡是损害人民群众利益的事情，我们必须坚决反对，不论是谁干的。", source: "《为人民服务》1944年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 128, text: "我们的干部，不管是哪一级，都是人民的公仆，都应该关心人民，为人民服务。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 129, text: "要关心群众的生活，注意工作方法。", source: "《关心群众生活，注意工作方法》1934年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 130, text: "我们要和群众在一起，要从群众中来，到群众中去，要把群众的意见集中起来，再到群众中坚持下去。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 131, text: "要使群众认识自己的利益，并且团结起来，为自己的利益而奋斗。", source: "《关心群众生活，注意工作方法》1934年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 132, text: "我们的一切工作，都是为了人民群众的利益，都是为了人民群众的解放。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 133, text: "脱离群众，就会失去力量。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 134, text: "党的工作的出发点和落脚点，都是为了人民群众的利益。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 135, text: "我们要善于把党的政策变为群众的行动，善于把群众中好的经验总结起来，成为党的政策。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 136, text: "我们党的工作，就是要联系群众，就是要为群众服务，就是要依靠群众。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 137, text: "人民群众是历史的主人，是推动历史前进的根本力量。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 138, text: "我们的党，我们的军队，我们的一切工作，都是为人民群众服务的。", source: "《为人民服务》1944年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 139, text: "共产党员应该是实事求是的，是和人民群众联系在一起的。", source: "《整顿党的作风》1942年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 140, text: "凡是人民群众的正确意见，我们应该坚决支持，凡是人民群众的错误意见，我们应该耐心说服。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 141, text: "我们的责任，是向人民负责，向历史负责。", source: "《为人民服务》1944年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 142, text: "人民群众的实践，是检验真理的唯一标准。", source: "《实践论》1937年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 143, text: "我们要尊重群众的首创精神，要善于发现和总结群众的经验。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 144, text: "群众是我们力量的源泉，是我们胜利的根本。", source: "《论联合政府》1945年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 145, text: "我们的一切工作都要经过群众，要依靠群众，要向群众学习，要为群众服务。", source: "《关于领导方法的若干问题》1943年", tag: "群众路线", context: "脱离了群众，就失去了力量的源泉。真正的智慧，藏在人民之中。" },
  { id: 146, text: "战争的目的在于消灭战争。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 147, text: "政治是不流血的战争，战争是流血的政治。", source: "《战争和战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 148, text: "知己知彼，百战不殆。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 149, text: "游击战争在整个革命战争中占有非常重要的战略地位。", source: "《抗日游击战争的战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 150, text: "战争是政治的继续，政治是战争的先导。", source: "《战争和战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 151, text: "保存自己，消灭敌人，这就是战争的目的，这就是战争的基本原则。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 152, text: "积极防御，又叫攻势防御，又叫决战防御。消极防御，又叫专守防御，又叫单纯防御。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 153, text: "战争的胜负，主要地决定于作战双方的军事、政治、经济、自然诸条件，这是没有疑义的。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 154, text: "战略上藐视敌人，战术上重视敌人。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 155, text: "我们的战略方针，应该是运动战为主，而以游击战辅助之。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 156, text: "人民战争是中国革命战争的基本形式。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 157, text: "战争的伟力之最深厚的根源，存在于民众之中。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 158, text: "兵民是胜利之本。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 159, text: "军队须和民众打成一片，使军队在民众眼睛中看成是自己的军队，这个军队便无敌于天下。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 160, text: "游击战争的基本原则是：保存自己，消灭敌人。", source: "《抗日游击战争的战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 161, text: "在战略上，我们以一当十；在战术上，我们以十当一，这是我们制胜敌人的根本法则之一。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 162, text: "集中兵力打歼灭战，是我军战略战术的基本原则。", source: "《集中优势兵力，各个歼灭敌人》1946年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 163, text: "军队的战斗力，是由人的因素和物的因素构成的，但人是决定的因素。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 164, text: "战争的规律——这是任何指导战争的人不能不研究和不能不解决的问题。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 165, text: "战争是力量的竞赛，但力量在战争过程中变化其原来的形态。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 166, text: "我军作战的基本方针，是以歼灭敌人有生力量为主要目标，不以保守或夺取地方为主要目标。", source: "《集中优势兵力，各个歼灭敌人》1946年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 167, text: "一切战争指导规律，依照历史的发展而发展，依照战争的发展而发展。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 168, text: "战争的目的不是别的，就是'保存自己，消灭敌人'。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 169, text: "没有正确的政治，就不能有正确的军事。", source: "《战争和战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 170, text: "我军的战略战术，是建立在人民战争的基础上的。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 171, text: "战争的特点，就是敌我双方都力图消灭对方，保存自己。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 172, text: "战争是最高形式的斗争，是解决阶级与阶级、民族与民族、国家与国家、政治集团与政治集团之间矛盾的最高斗争形式。", source: "《战争和战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 173, text: "我们的原则是：只要我军尚有战斗力，就要坚决打击敌人，不能轻易放弃战机。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 174, text: "军队是执行革命的政治任务的武装集团。", source: "《战争和战略问题》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 175, text: "一切军事行动的指导原则，都是建立在一个基本原则上，就是：尽可能地保存自己的力量，消灭敌人的力量。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 176, text: "我们的战略是'以一当十'，我们的战术是'以十当一'，这是我们制胜强敌的根本法则。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 177, text: "战争的规律是：以强胜弱，以众胜寡，以有备胜无备，以勇敢胜怯懦。", source: "《中国革命战争的战略问题》1936年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 178, text: "打仗的时候，要集中兵力打歼灭战，不打击溃战。", source: "《集中优势兵力，各个歼灭敌人》1946年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 179, text: "我们的战略方针，是积极防御，反对消极防御。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 180, text: "战争的基本问题是保存自己消灭敌人。", source: "《论持久战》1938年", tag: "军事思想", context: "在战略上藐视困难，在战术上重视每一个细节——这是成事的基本法则。" },
  { id: 181, text: "党的力量来自组织。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 182, text: "惩前毖后，治病救人。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 183, text: "批评和自我批评是我们党的优良传统，是我们党区别于其他任何政党的显著标志之一。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 184, text: "党委要善于集中正确意见，善于综合大多数同志的意见，然后作出决定。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 185, text: "我们党的干部政策，应该是任人唯贤，反对任人唯亲。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 186, text: "共产党员应该是实事求是的，是和人民群众联系在一起的，是有自我批评精神的。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 187, text: "我们党是在一个几万万人的大民族中领导伟大革命斗争的党，没有多数才德兼备的领导干部，是不能完成其历史任务的。", source: "《中国共产党在民族战争中的地位》1938年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 188, text: "党的纪律是铁的纪律，必须执行，不能违反。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 189, text: "民主集中制是党的根本组织原则。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 190, text: "我们的党，从它一开始，就是一个以马克思列宁主义的理论为基础的党，这是因为这种理论是正确的。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 191, text: "党的团结是党的生命。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 192, text: "党的统一和团结，是党的生命，是党的力量的源泉。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 193, text: "我们应当提倡每个党员都要认真学习马克思列宁主义，学习毛泽东思想。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 194, text: "党的领导，主要是政治领导、思想领导和组织领导。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 195, text: "一个好的共产党员，应该是一个全心全意为人民服务的人。", source: "《为人民服务》1944年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 196, text: "党的工作中的主观主义、官僚主义和宗派主义，是党的工作的大敌。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 197, text: "我们党的工作，应该是以人民群众的利益为出发点，以人民群众的利益为归宿。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 198, text: "共产党员必须随时准备坚持真理，因为任何真理都是符合于人民利益的；共产党员必须随时准备修正错误，因为任何错误都是不符合于人民利益的。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 199, text: "一个政党，一个国家，一个民族，如果一切从本本出发，思想僵化，迷信盛行，那它就不能前进，它的生机就停止了，就要亡党亡国。", source: "《实践论》1937年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 200, text: "我们共产党人，不论在任何艰难困苦的场合，只要还有一个人，这个人就要继续战斗下去。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 201, text: "党的路线正确就有一切，没有人可以有人，没有枪可以有枪，没有政权可以有政权。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 202, text: "党的纪律是统一的，党员必须服从党的决定。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 203, text: "我们党的干部，应该是有理论修养的，有实践经验的，有工作能力的。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 204, text: "在党内，不允许有不受纪律约束的特殊党员。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 205, text: "党的工作必须联系实际，联系群众，联系党的政策。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 206, text: "我们的党，是一个有纪律的、有马克思列宁主义的理论武装的、采取自我批评方法的、联系人民群众的党。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 207, text: "党的纪律，是党的团结和统一的保证，是党的战斗力的源泉。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 208, text: "党的工作，要从实际出发，要联系群众，要批评和自我批评。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 209, text: "我们党的最高利益，就是全国人民的最高利益。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 210, text: "党的工作的好坏，关键在于领导，关键在于干部。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 211, text: "我们要建立一个廉洁的、为人民服务的政府。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 212, text: "共产党员要做到：在任何困难的情况下，都要坚持党的路线，执行党的决定。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 213, text: "党的工作，要从群众中来，到群众中去，要联系实际，要批评和自我批评。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 214, text: "我们党的历史，是一部斗争的历史，是一部在斗争中成长和发展的历史。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 215, text: "党的建设，是党的一切工作的基础，是党的事业胜利的保证。", source: "《关于健全党委制》1948年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 216, text: "我们的党，必须不断地加强自身的建设，提高自己的战斗力。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 217, text: "党的工作，要坚持实事求是，坚持群众路线，坚持批评和自我批评。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 218, text: "我们要建设一个强大的党，一个有战斗力的党，一个能够领导人民完成革命任务的党。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 219, text: "党的工作，必须以马克思列宁主义为指导，必须联系实际，必须联系群众。", source: "《整顿党的作风》1942年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 220, text: "我们的党，是一个有着光荣历史的党，是一个为人民服务的党，是一个不断进步的党。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 221, text: "党的领导，是中国革命胜利的根本保证。", source: "《论联合政府》1945年", tag: "党的建设", context: "批评与自我批评，是一个组织保持活力、不断进步的根本动力。" },
  { id: 222, text: "统一战线、武装斗争、党的建设，是中国共产党在中国革命中战胜敌人的三个法宝，三个主要的法宝。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 223, text: "团结一切可以团结的力量，调动一切积极因素，为建设社会主义服务。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 224, text: "我们的政策，是以发展进步势力，争取中间势力，孤立顽固势力为基本策略。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 225, text: "在统一战线中，既要有统一，又要有独立；既要联合，又要斗争。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 226, text: "抗日民族统一战线是中国共产党领导的，以工农联盟为基础的，包括一切抗日阶级和阶层的广泛的政治联盟。", source: "《论新阶段》1938年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 227, text: "在统一战线问题上，我们的原则是：又联合，又斗争；以斗争求团结，则团结存；以退让求团结，则团结亡。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 228, text: "我们的政策，不是孤立的，而是联合的；不是排他的，而是包容的。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 229, text: "中国共产党必须善于把马克思列宁主义的普遍真理和中国革命的具体实践完全地恰当地统一起来，就是说，理论和实践要相统一。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 230, text: "在统一战线中，我们既要坚持原则，又要灵活运用策略。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 231, text: "我们的统一战线，是建立在共同利益的基础上的，是为了共同的目标而联合的。", source: "《论新阶段》1938年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 232, text: "团结就是力量。只有团结，才能战胜敌人，才能完成革命任务。", source: "《论联合政府》1945年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 233, text: "我们要善于利用矛盾，善于分化敌人，善于团结一切可以团结的力量。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 234, text: "统一战线的基础，是工农联盟，是工人阶级和农民阶级的联合。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 235, text: "我们的统一战线，是在共产党领导下的，是以工农联盟为基础的。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 236, text: "在统一战线中，我们要坚持独立自主的原则，不能被别人牵着鼻子走。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 237, text: "我们的政策，是团结一切可以团结的力量，孤立最顽固的敌人。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 238, text: "统一战线是一种策略，是为了实现党的战略目标服务的。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 239, text: "我们要善于在复杂的情况下，找到正确的方向，坚持正确的路线。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 240, text: "团结一切可以团结的力量，是我们党的一贯方针。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 241, text: "我们的统一战线，是建立在共同反对帝国主义和封建主义的基础上的。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 242, text: "在统一战线中，我们要坚持党的领导，坚持无产阶级的领导权。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 243, text: "我们的政策，是既联合又斗争，在斗争中求团结，在团结中求发展。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 244, text: "统一战线的成功，关键在于党的正确领导和正确的统一战线政策。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 245, text: "我们要善于利用敌人内部的矛盾，善于分化瓦解敌人。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 246, text: "统一战线的基本原则，是在坚持党的领导的前提下，团结一切可以团结的力量。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 247, text: "我们的统一战线，是为了完成民族民主革命的任务而建立的。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 248, text: "在统一战线中，我们要坚持原则，反对投降主义和关门主义。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 249, text: "我们要善于在不同的历史时期，采取不同的统一战线策略。", source: "《目前抗日统一战线中的策略问题》1940年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 250, text: "统一战线是中国革命的三大法宝之一，是我们战胜敌人的重要武器。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 251, text: "我们的统一战线政策，是在坚持党的独立性的前提下，广泛联合一切可以联合的力量。", source: "《<共产党人>发刊词》1939年", tag: "统一战线", context: "团结一切可以团结的力量，这是成就大事的不二法门。" },
  { id: 252, text: "我们看问题不要从抽象的定义出发，而要从客观存在的事实出发，从分析这些事实中找出方针、政策、办法来。", source: "《反对党八股》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 253, text: "我们的眼睛，要向下看，不要向上看。", source: "《关心群众生活，注意工作方法》1934年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 254, text: "学习马克思主义，是要我们用辩证唯物主义和历史唯物主义的观点去观察世界，观察社会，观察文学和艺术。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 255, text: "我们应该是实事求是的，不是主观主义的，不是形式主义的，不是教条主义的。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 256, text: "弄清楚所研究的问题发生的一定的时间和一定的空间，把问题当作一定历史条件下的历史过程去研究。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 257, text: "片面性就是不知道全面地看问题。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 258, text: "要使全党的工作，成为有机的统一的整体，就要求每一个党员都要有正确的思想方法。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 259, text: "我们的任务，是要把马克思列宁主义的理论和中国革命的实践结合起来，使之成为中国化的马克思主义。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 260, text: "解决问题，要抓主要矛盾，要找到解决问题的关键所在。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 261, text: "我们研究问题，要从实际出发，要从具体情况出发，不能从抽象的原则出发。", source: "《反对本本主义》1930年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 262, text: "要有正确的思想方法，就要学习辩证法，学习唯物主义。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 263, text: "我们看问题，要全面，要看到问题的各个方面，不能只看一面。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 264, text: "我们的思想方法，应该是辩证的，而不是形而上学的。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 265, text: "要善于分析，要善于综合，要善于从个别到一般，从一般到个别。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 266, text: "我们要善于把握事物的主要矛盾和矛盾的主要方面。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 267, text: "要坚持实事求是，就要反对主观主义，反对形式主义，反对教条主义。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 268, text: "我们的思想，要跟上时代的发展，要不断地更新，不断地进步。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 269, text: "要善于从现象看本质，从个别看一般，从局部看全局。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 270, text: "我们研究问题，既要看到它的普遍性，又要看到它的特殊性。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 271, text: "要有正确的思想方法，就要学会辩证地看问题，全面地看问题，历史地看问题。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 272, text: "我们的思想方法，是马克思列宁主义的思想方法，是辩证唯物主义的思想方法。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 273, text: "要善于抓住问题的关键，找到解决问题的突破口。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 274, text: "我们要善于从实际出发，而不是从本本出发，从原则出发。", source: "《反对本本主义》1930年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 275, text: "要善于总结经验，善于从成功和失败中学习。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 276, text: "我们的思想，要随着实践的发展而发展，要不断地更新，不断地进步。", source: "《实践论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 277, text: "要善于把握事物发展的规律，善于预见事物发展的趋势。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 278, text: "我们研究问题，要从实际出发，要从具体情况出发，要从历史条件出发。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 279, text: "要善于区分主要矛盾和次要矛盾，善于抓住主要矛盾。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 280, text: "我们的思想方法，要坚持唯物主义，反对唯心主义；坚持辩证法，反对形而上学。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 281, text: "要善于从全局出发，善于把握整体，善于协调各方面的关系。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 282, text: "我们研究问题，要有科学的态度，要实事求是，要尊重客观规律。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 283, text: "要善于运用马克思主义的立场、观点和方法，去分析和解决实际问题。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 284, text: "我们的思想，要与时俱进，要不断地学习，不断地进步。", source: "《整顿党的作风》1942年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 285, text: "要善于把握事物的本质，透过现象看本质，透过偶然看必然。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 286, text: "我们研究问题，要有全局观念，要从整体出发，不能只见树木，不见森林。", source: "《矛盾论》1937年", tag: "思想方法", context: "从实际出发，而非从本本出发——这是解决一切问题的思想前提。" },
  { id: 287, text: "批评和自我批评是我们党的优良传统，是我们党区别于其他任何政党的显著标志之一。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 288, text: "我们应该用批评和自我批评的方法，来克服我们队伍中的各种错误思想。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 289, text: "惩前毖后，治病救人，这是我们对待犯错误的同志的正确方针。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 290, text: "我们的批评，要以事实为根据，要对事不对人，要出于公心，不能搞人身攻击。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 291, text: "批评要正确，要有建设性，要帮助同志改正错误，而不是打击同志。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 292, text: "自我批评是一种勇气，是一种负责任的态度，是一种进步的表现。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 293, text: "我们要勇于承认错误，勇于改正错误，这是一个共产党员应有的品质。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 294, text: "批评和自我批评，是我们党保持先进性和纯洁性的重要手段。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 295, text: "我们的党，是一个善于自我批评的党，是一个不断进步的党。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 296, text: "要善于批评，也要善于接受批评，这是一个成熟的共产党员应有的素质。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 297, text: "我们的批评，要出于公心，要为了党的利益，为了人民的利益，而不是为了个人的私利。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 298, text: "批评和自我批评，是我们党克服错误、保持先进性的重要武器。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 299, text: "我们要敢于批评，敢于自我批评，这是一种革命的精神，是一种进步的力量。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 300, text: "批评要有理有据，要实事求是，不能无中生有，不能夸大其词。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 301, text: "我们的自我批评，要真诚，要深刻，要找到问题的根源，而不是走过场。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 302, text: "批评和自我批评，是我们党的生命力所在，是我们党不断进步的动力。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 303, text: "我们要善于从批评中学习，从自我批评中成长，不断提高自己的思想水平和工作能力。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 304, text: "批评要及时，要准确，要有针对性，不能等到问题积累到很严重的时候才批评。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 305, text: "我们的批评，要帮助同志进步，而不是打击同志的积极性。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 306, text: "自我批评是一种勇气，是一种担当，是一种对党和人民负责的态度。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 307, text: "我们的党，正是通过不断的批评和自我批评，才能不断地纠正错误，不断地前进。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 308, text: "批评和自我批评，是我们党的优良传统，我们要把这个传统发扬光大。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 309, text: "我们要勤于自我批评，善于自我批评，把自我批评作为自己进步的阶梯。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 310, text: "批评要出于爱护，要出于帮助，要出于对同志负责的精神。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 311, text: "我们的批评和自我批评，是为了使我们的党更加强大，使我们的工作做得更好。", source: "《整顿党的作风》1942年", tag: "批评与自我批评", context: "勇于承认错误，才是真正的强大；逃避批评，只会让问题越积越深。" },
  { id: 312, text: "中国人民的解放事业，是世界无产阶级革命事业的一部分。", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 313, text: "我们的革命，不是孤立的，而是世界革命的一部分。", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 314, text: "中国必须独立，中国必须解放，中国的事情必须由中国人民自己作主张，自己来处理，不容许任何帝国主义国家再有一丝一毫的干涉。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 315, text: "中国人民站起来了！", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 316, text: "我们是主张自力更生的。我们希望有外援，但是我们不能依赖它，我们依靠自己的努力，依靠全体军民的创造力。", source: "《论联合政府》1945年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 317, text: "中国人民有志气，有能力，一定要在不远的将来，赶上和超过世界先进水平。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 318, text: "我们的国家是一个统一的多民族的国家，各民族一律平等。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 319, text: "帝国主义是战争的根源，是世界人民的公敌。", source: "《论持久战》1938年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 320, text: "全世界无产者，联合起来！", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 321, text: "中国革命的胜利，是马克思列宁主义在中国的胜利，是中国共产党领导中国人民的胜利。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 322, text: "我们的国家，是一个有着悠久历史和灿烂文化的国家，是一个有着伟大人民的国家。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 323, text: "中国人民从此站立起来了，中国人的命运从此掌握在自己手里了。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 324, text: "我们的国家，是一个独立自主的国家，我们不允许任何外国干涉我们的内政。", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 325, text: "中国革命的胜利，是中国人民长期斗争的结果，是中国共产党正确领导的结果。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 326, text: "我们要建设一个强大的、繁荣的、文明的社会主义国家。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 327, text: "中国人民是勤劳勇敢的人民，是有着伟大创造力的人民。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 328, text: "我们的国家，是一个爱好和平的国家，我们不侵略别人，也不允许别人侵略我们。", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 329, text: "中国革命的胜利，开辟了中国历史的新纪元，是中国历史上的伟大转折。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 330, text: "我们要学习一切民族、一切国家的长处，学习他们的科学技术，学习他们的先进经验。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 331, text: "中国人民热爱和平，但是为了保卫和平，从不也永不害怕反抗侵略战争。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 332, text: "我们的国家，是一个主权独立的国家，我们的内政不容许任何外国干涉。", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 333, text: "中国革命的胜利，证明了马克思列宁主义在中国的正确性，证明了中国共产党的正确领导。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 334, text: "我们要建设一个独立、民主、和平、统一、富强的新中国。", source: "《论联合政府》1945年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 335, text: "中国人民的革命，是世界人民解放事业的重要组成部分。", source: "《论人民民主专政》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 336, text: "我们的国家，是一个有着光明前途的国家，是一个正在走向繁荣富强的国家。", source: "《中国人民站起来了》1949年", tag: "国际主义", context: "中国人民站起来了。自立自强，是一个民族最深沉的底气。" },
  { id: 337, text: "文艺是从属于政治的，但是又反转来给予伟大影响于政治。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 338, text: "革命的文艺，应当根据实际生活创造出各种各样的人物来，帮助群众推动历史的前进。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 339, text: "我们的文学艺术都是为人民大众的，首先是为工农兵的。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 340, text: "百花齐放，百家争鸣。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 341, text: "艺术和政治的关系，就是艺术的标准和政治的标准的关系。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 342, text: "文艺工作者必须到群众中去，到火热的斗争中去，观察、体验、研究、分析一切人，一切阶级，一切群众，一切生动的生活形式和斗争形式，一切文学和艺术的原始材料，然后才有可能进入创作过程。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 343, text: "文艺批评有两个标准，一个是政治标准，一个是艺术标准。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 344, text: "我们的文艺，是为人民服务的文艺，是为革命服务的文艺。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 345, text: "革命文艺，是整个革命机器的一个组成部分，是团结人民、教育人民、打击敌人、消灭敌人的有力的武器。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 346, text: "文艺工作者要深入生活，深入群众，才能创作出真正反映人民生活的作品。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 347, text: "我们的文艺，要反映人民的生活，要表现人民的思想感情，要为人民服务。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 348, text: "文艺工作者要有正确的立场，要站在人民的立场上，为人民服务。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 349, text: "我们的文艺，要继承和发扬中华民族的优秀文化传统，同时要吸收外国的先进文化。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 350, text: "文艺创作，要有生活基础，要有思想深度，要有艺术水平。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 351, text: "我们的文艺，要有正确的政治方向，要有高尚的艺术品质，要有广泛的群众基础。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 352, text: "文艺工作者要不断提高自己的思想水平和艺术水平，才能创作出更好的作品。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 353, text: "我们的文艺，要反对庸俗化，要反对低级趣味，要追求高尚的艺术品质。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 354, text: "文艺工作者要有责任感，要对人民负责，对历史负责，对艺术负责。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 355, text: "我们的文艺，要有民族特色，要有时代精神，要有人民性。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 356, text: "文艺创作，要从生活出发，要从人民出发，要从实践出发。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 357, text: "我们的文艺，要服务于人民，服务于社会主义，服务于革命。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 358, text: "文艺工作者要深入生活，体验生活，才能创作出真实感人的作品。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 359, text: "我们的文艺，要有正确的世界观，要有进步的思想，要有高尚的情操。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 360, text: "文艺批评，要坚持实事求是，要坚持客观公正，不能主观臆断，不能以偏概全。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 361, text: "我们的文艺，要继承传统，要推陈出新，要在继承中发展，在发展中创新。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 362, text: "文艺工作者要有广博的知识，要有丰富的生活经验，要有深厚的艺术修养。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 363, text: "我们的文艺，要有强烈的时代感，要反映时代的精神，要表现时代的主题。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 364, text: "文艺创作，要有独特的艺术风格，要有鲜明的个性，要有创新精神。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 365, text: "我们的文艺，要有正确的价值取向，要弘扬真善美，要批判假恶丑。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 366, text: "文艺工作者要有高度的社会责任感，要用自己的作品为人民服务，为社会服务。", source: "《在延安文艺座谈会上的讲话》1942年", tag: "文化艺术", context: "文艺的生命力，在于它是否真正根植于人民的土壤之中。" },
  { id: 367, text: "发展经济，保障供给，这是我们的经济工作和财政工作的总方针。", source: "《抗日时期的经济问题和财政问题》1942年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 368, text: "农业是国民经济的基础，工业是国民经济的主导。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 369, text: "我们要建设一个工业化的、高度文明的社会主义国家。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 370, text: "发展是硬道理，经济建设是党和国家的中心工作。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 371, text: "我们要在一个相当长的时期内，逐步实现国家的社会主义工业化。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 372, text: "生产力是社会发展的最终决定力量。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 373, text: "我们的任务，是要在中国建设一个工业化的、高度文明的、民主的社会主义国家。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 374, text: "我们要大力发展生产力，不断提高人民的生活水平。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 375, text: "农业生产是我国国民经济的基础，必须大力发展农业生产。", source: "《关于农业合作化问题》1955年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 376, text: "我们要建设一个强大的、繁荣的、文明的社会主义国家，就必须大力发展经济。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 377, text: "工业化是国家富强的基础，是实现社会主义现代化的必由之路。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 378, text: "我们要勤俭建国，艰苦奋斗，不断提高人民的生活水平。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 379, text: "我们要大力发展科学技术，推动经济社会的发展。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 380, text: "经济建设是党和国家的中心工作，一切工作都要服从于经济建设的需要。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 381, text: "我们要建立一个完整的工业体系，实现国家的工业化。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 382, text: "农业合作化，是农村经济发展的必由之路，是农民走向共同富裕的正确道路。", source: "《关于农业合作化问题》1955年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 383, text: "我们要大力发展教育事业，培养大批建设社会主义的人才。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 384, text: "经济工作，要从实际出发，要因地制宜，不能一刀切。", source: "《抗日时期的经济问题和财政问题》1942年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 385, text: "我们要大力发展农业生产，保证粮食的充足供应。", source: "《关于农业合作化问题》1955年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 386, text: "我们要建设一个高度发达的社会主义经济，为实现共产主义创造物质基础。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 387, text: "工农业生产的发展，是国家富强的根本，是人民生活改善的基础。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 388, text: "我们要大力发展交通运输业，促进经济的发展和人民生活的改善。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 389, text: "经济建设，要坚持自力更生的原则，同时也要积极引进外资和先进技术。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 390, text: "我们要大力发展文化教育事业，提高全民族的文化素质。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 391, text: "农业的发展，是工业发展的基础，是整个国民经济发展的基础。", source: "《关于农业合作化问题》1955年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 392, text: "我们要建立一个完善的社会主义经济制度，保证经济的持续健康发展。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 393, text: "经济建设，要坚持勤俭节约的原则，反对铺张浪费。", source: "《在中国共产党第七届中央委员会第二次全体会议上的报告》1949年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 394, text: "我们要大力发展科学技术，把科学技术作为第一生产力。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 395, text: "农业合作化，是实现农业现代化的重要途径，是农民走向共同富裕的必由之路。", source: "《关于农业合作化问题》1955年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 396, text: "我们要建设一个现代化的、强大的社会主义国家，就必须大力发展经济，提高综合国力。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 397, text: "工业是国民经济的主导，农业是国民经济的基础，两者相互依存，相互促进。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 398, text: "我们要大力发展对外贸易，积极参与国际经济合作，促进国内经济的发展。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 399, text: "经济建设，要坚持以人民为中心，要让人民群众共享经济发展的成果。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 400, text: "我们要大力发展社会主义经济，不断提高人民的物质文化生活水平。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 401, text: "农业生产的发展，是解决人民温饱问题的根本，是国家稳定发展的基础。", source: "《关于农业合作化问题》1955年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 402, text: "我们要建立一个完整的国民经济体系，实现国家的全面现代化。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 403, text: "经济建设，要坚持计划性，要按照客观规律办事，不能主观蛮干。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 404, text: "我们要大力发展教育和科学技术，为经济建设提供强大的人才支撑和技术支撑。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 405, text: "工农业生产的发展，要坚持自力更生，艰苦奋斗，不能依赖外援。", source: "《论联合政府》1945年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 406, text: "我们要建设一个富强、民主、文明的社会主义现代化国家。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 407, text: "经济建设，是党和国家的根本任务，是实现中华民族伟大复兴的物质基础。", source: "《关于正确处理人民内部矛盾的问题》1957年", tag: "经济建设", context: "发展是硬道理。脚踏实地地建设，才是改变命运的根本途径。" },
  { id: 408, text: "星星之火，可以燎原。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 409, text: "它是站在海岸遥望海中已经看得见桅杆尖头了的一只航船，它是立于高山之巅远看东方已见光芒四射喷薄欲出的一轮朝日，它是躁动于母腹中的快要成熟了的一个婴儿。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 410, text: "中国革命的高潮快要到来了。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 411, text: "农村包围城市，武装夺取政权。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 412, text: "我们要有坚定的信心，相信中国革命一定能够取得最后的胜利。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 413, text: "革命的力量，是从小到大，从弱到强，从局部到全局，逐步发展起来的。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 414, text: "我们的革命根据地，是中国革命的战略基地，是革命力量发展壮大的基础。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 415, text: "中国革命，必须走农村包围城市的道路，这是中国革命的特殊规律。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 416, text: "我们要坚定信心，克服困难，坚持斗争，一定能够取得革命的最后胜利。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 417, text: "革命根据地的建立和发展，是中国革命胜利的重要条件。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 418, text: "我们要在农村建立革命根据地，积累革命力量，等待时机，夺取全国政权。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 419, text: "中国革命的道路，是曲折的，但前途是光明的。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 420, text: "我们要有长期奋斗的准备，要有艰苦奋斗的精神，要有必胜的信心。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 421, text: "革命的力量，在于人民群众，在于广大的工农群众。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 422, text: "我们要善于把握革命的时机，善于利用有利的形势，推动革命的发展。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 423, text: "中国革命的胜利，是中国人民长期斗争的结果，是历史发展的必然。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 424, text: "我们要坚持走群众路线，依靠人民群众，才能取得革命的最后胜利。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 425, text: "革命根据地的建设，是中国革命的战略任务，是革命胜利的重要保证。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 426, text: "我们要有战略眼光，要看到革命发展的大趋势，不能被暂时的困难所吓倒。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" },
  { id: 427, text: "中国革命，是世界革命的一部分，中国革命的胜利，将对世界革命产生深远的影响。", source: "《星星之火，可以燎原》1930年", tag: "星火燎原", context: "星星之火，可以燎原。任何伟大的事业，都从一个微小的开始。" }
];

module.exports = quotes;